from collections import deque
class Solution:
    def maxMoves(self, kx, ky, positions):
        m = len(positions)
        pts = [(kx, ky)] + [tuple(p) for p in positions]
        cnt = m + 1
        moves = [(-2, -1), (-2, 1), (-1, -2), (-1, 2), (1, -2), (1, 2), (2, -1), (2, 1)]
        dist = [[0] * cnt for _ in range(cnt)]
        for i, (sx, sy) in enumerate(pts):
            d = [[-1] * 50 for _ in range(50)]
            d[sx][sy] = 0
            q = deque([(sx, sy)])
            while q:
                x, y = q.popleft()
                for dx, dy in moves:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < 50 and 0 <= ny < 50 and d[nx][ny] == -1:
                        d[nx][ny] = d[x][y] + 1
                        q.append((nx, ny))
            for j, (tx, ty) in enumerate(pts):
                dist[i][j] = d[tx][ty]
        memo = {}
        def rec(mask, last, alice):
            if mask == 0:
                return 0
            key = (mask, last, alice)
            if key in memo:
                return memo[key]
            best = None
            mm = mask
            while mm:
                low = mm & (-mm)
                j = low.bit_length() - 1
                val = dist[last][j + 1] + rec(mask ^ low, j + 1, not alice)
                if best is None:
                    best = val
                elif alice:
                    best = max(best, val)
                else:
                    best = min(best, val)
                mm ^= low
            memo[key] = best
            return best
        return rec((1 << m) - 1, 0, True)

