var maxMoves = function(kx, ky, positions) {
    const m = positions.length;
    const pts = [[kx, ky], ...positions.map(p => [p[0], p[1]])];
    const cnt = m + 1;
    const moveDeltas = [[-2, -1], [-2, 1], [-1, -2], [-1, 2], [1, -2], [1, 2], [2, -1], [2, 1]];
    const dist = Array.from({ length: cnt }, () => new Array(cnt).fill(0));
    for (let i = 0; i < cnt; i++) {
        const [sx, sy] = pts[i];
        const d = Array.from({ length: 50 }, () => new Array(50).fill(-1));
        d[sx][sy] = 0;
        const queue = [[sx, sy]];
        let head = 0;
        while (head < queue.length) {
            const [x, y] = queue[head++];
            for (const [dx, dy] of moveDeltas) {
                const nx = x + dx, ny = y + dy;
                if (nx >= 0 && nx < 50 && ny >= 0 && ny < 50 && d[nx][ny] === -1) {
                    d[nx][ny] = d[x][y] + 1;
                    queue.push([nx, ny]);
                }
            }
        }
        for (let j = 0; j < cnt; j++) {
            const [tx, ty] = pts[j];
            dist[i][j] = d[tx][ty];
        }
    }
    const full = (1 << m) - 1;
    const dp = [];
    for (let mask = 0; mask <= full; mask++) dp.push(new Array(cnt).fill(0));
    for (let mask = 1; mask <= full; mask++) {
        let bits = 0, t = mask;
        while (t) { bits += t & 1; t >>= 1; }
        const captured = m - bits;
        const alice = (captured % 2 === 0);
        const row = dp[mask];
        for (let last = 0; last < cnt; last++) {
            let best = null;
            let mm = mask;
            while (mm) {
                const low = mm & (-mm);
                let j = 0, low2 = low;
                while (low2 > 1) { low2 >>>= 1; j++; }
                const val = dist[last][j + 1] + dp[mask ^ low][j + 1];
                if (best === null) best = val;
                else if (alice) { if (val > best) best = val; }
                else { if (val < best) best = val; }
                mm ^= low;
            }
            row[last] = best;
        }
    }
    return dp[full][0];
};
